const articles = $input.all();

// Sort by date and take top 5
const top5 = articles
  .sort((a, b) => new Date(b.json.pubDate) - new Date(a.json.pubDate))
  .slice(0, 5);

return top5.map(item => ({
  json: {
    title: item.json.title,
    link: item.json.link,
    pubDate: item.json.pubDate,
    contentSnippet: item.json.contentSnippet || ''
  }
}));

const articles = $input.all();
const results = [];

for (const item of articles) {
  const { title, contentSnippet, link, pubDate } = item.json;

  const prompt = `Summarize the following news in maximum 50 words in a clear and engaging way:\n\nTitle: ${title}\n\nContent: ${contentSnippet}`;

  try {
    const response = await $http.request({
      method: 'POST',
      url: 'https://api.openai.com/v1/chat/completions',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer YOUR_OPENAI_API_KEY'
      },
      body: {
        model: 'gpt-3.5-turbo',
        messages: [{ role: 'user', content: prompt }],
        max_tokens: 100
      },
      json: true
    });

    const summary = response.choices?.[0]?.message?.content?.trim()
      || contentSnippet.split(' ').slice(0, 50).join(' ') + '...';

    results.push({ json: { title, link, pubDate, summary } });

  } catch (error) {
    // Fallback to first 50 words if API fails
    const fallback = contentSnippet.split(' ').slice(0, 50).join(' ') + '...';
    results.push({ json: { title, link, pubDate, summary: fallback } });
  }
}

return results;

// ✅ Use .all() to collect all items properly
const articles = $input.all();

const headerColors = [
  { bg: '#FF6B6B', light: '#fff0f0', icon: '🔴' },
  { bg: '#4ECDC4', light: '#f0fffe', icon: '🟢' },
  { bg: '#45B7D1', light: '#f0f9ff', icon: '🔵' },
  { bg: '#96CEB4', light: '#f0fff5', icon: '🟡' },
  { bg: '#DDA0DD', light: '#fdf0ff', icon: '🟣' }
];

const cards = articles.map((item, index) => {
  const { title, link, pubDate, summary } = item.json;
  const color = headerColors[index];
  const dateStr = new Date(pubDate).toLocaleDateString('en-IN', {
    weekday: 'short', year: 'numeric', month: 'short', day: 'numeric'
  });

  return `
    <table width="100%" cellpadding="0" cellspacing="0" style="
      margin-bottom: 20px;
      border-radius: 12px;
      overflow: hidden;
      box-shadow: 0 2px 8px rgba(0,0,0,0.1);
    ">
      <tr>
        <td style="
          background: ${color.bg};
          padding: 14px 18px;
          border-radius: 12px 12px 0 0;
        ">
          <table width="100%" cellpadding="0" cellspacing="0">
            <tr>
              <td>
                <span style="
                  color: white; font-size: 11px;
                  font-weight: bold; text-transform: uppercase;
                  letter-spacing: 1px; opacity: 0.9;
                ">${color.icon} News ${String(index + 1).padStart(2, '0')}</span>
              </td>
              <td align="right">
                <span style="color:white; font-size:11px; opacity:0.85;">
                  📅 ${dateStr}
                </span>
              </td>
            </tr>
          </table>
        </td>
      </tr>
      <tr>
        <td style="background:${color.light}; padding:16px 18px 8px;">
          <a href="${link}" style="
            color: ${color.bg}; font-size: 16px;
            font-weight: bold; text-decoration: none;
            line-height: 1.5; display: block;
          ">${title}</a>
        </td>
      </tr>
      <tr>
        <td style="background:${color.light}; padding:8px 18px 16px;">
          <p style="
            color: #444; font-size: 13px;
            line-height: 1.7; margin: 0 0 14px;
          ">${summary}</p>
          <a href="${link}" style="
            display: inline-block; background: ${color.bg};
            color: white; font-size: 12px; font-weight: bold;
            padding: 8px 18px; border-radius: 25px;
            text-decoration: none; letter-spacing: 0.5px;
          ">Read Full Story →</a>
        </td>
      </tr>
    </table>`;
}).join('');

// ✅ Build Telegram message
const telegramLines = articles.map((item, index) => {
  const { title, link, summary } = item.json;
  const icons = ['🔴','🟢','🔵','🟡','🟣'];
  return `${icons[index]} *News ${String(index + 1).padStart(2, '0')}*\n*${title}*\n${summary}\n[Read More](${link})`;
}).join('\n\n─────────────\n\n');

const today = new Date().toLocaleDateString('en-IN', {
  weekday: 'long', year: 'numeric',
  month: 'long', day: 'numeric'
});

const html = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
</head>
<body style="margin:0; padding:0; background:#f0f2f5;">
  <div style="max-width:640px; margin:auto; padding:20px; font-family:Arial,sans-serif;">

    <table width="100%" cellpadding="0" cellspacing="0" style="
      background: linear-gradient(135deg, #1a1a2e, #16213e, #0f3460);
      border-radius: 14px; margin-bottom: 24px; overflow: hidden;
    ">
      <tr>
        <td style="padding:30px 24px; text-align:center;">
          <div style="font-size:36px; margin-bottom:10px;">📰</div>
          <h1 style="color:white; margin:0 0 8px; font-size:24px;">
            Daily News Digest
          </h1>
          <p style="color:#aac4e0; margin:0; font-size:13px;">${today}</p>
          <div style="
            width:50px; height:3px;
            background:linear-gradient(to right, #FF6B6B, #4ECDC4);
            margin:14px auto 0; border-radius:2px;
          "></div>
          <p style="color:#aac4e0; font-size:12px; margin:10px 0 0;">
            🗞️ Top 5 Stories · AI Summarized
          </p>
        </td>
      </tr>
    </table>

    <div style="background:white; border-radius:10px; padding:10px;">
      <table width="100%" cellpadding="0" cellspacing="0">${cards}</table>
    </div>

    <table width="100%" cellpadding="0" cellspacing="0" style="
      background:#1a1a2e; border-radius:12px; margin-top:10px;
    ">
      <tr>
        <td style="padding:20px; text-align:center;">
          <p style="color:#aac4e0; font-size:12px; margin:0 0 6px;">
            Powered by <strong style="color:white;">n8n</strong> +
            <strong style="color:white;">AI Summarizer</strong>
          </p>
          <p style="color:#666; font-size:11px; margin:0;">
            <a href="#" style="color:#4ECDC4; text-decoration:none;">Unsubscribe</a> ·
            <a href="#" style="color:#4ECDC4; text-decoration:none;">View Online</a>
          </p>
        </td>
      </tr>
    </table>

  </div>
</body>
</html>`;

// ✅ KEY FIX — Return single item so both Email
// and Telegram can use .first() without pairing error
return [{
  json: {
    html,
    subject: `📰 Daily News Digest – ${today}`,
    telegramText: `📰 *Daily News Digest*\n_${today}_\n\n${telegramLines}`,
    articleCount: articles.length
  }
}];
